// ==========================================================================
// 7. SHEEP PRICES MONITOR ("HARGA DOMBA")
// ==========================================================================
function calculateSheepPriceStats() {
  const prices = window.Database.getPrices();
  if (!prices || prices.length === 0) {
    return {
      latestDate: "-",
      javaAvg: 0,
      nationalAvg: 0,
      javaChangePct: 0,
      nationalChangePct: 0,
      highPrice: 0,
      lowPrice: 0,
      trend: "stable",
      latestRecord: null
    };
  }

  const sorted = [...prices].sort((a, b) => new Date(a.tanggal) - new Date(b.tanggal));
  const latest = sorted[sorted.length - 1];
  const prev = sorted.length > 1 ? sorted[sorted.length - 2] : null;

  const javaAvg = latest.harga_jawa || 0;
  const nationalAvg = latest.harga_nasional || 0;
  const highPrice = latest.harga_tertinggi || 0;
  const lowPrice = latest.harga_terendah || 0;

  const prevJavaAvg = prev ? prev.harga_jawa : 0;
  const prevNationalAvg = prev ? prev.harga_nasional : 0;

  const javaChangePct = prevJavaAvg ? ((javaAvg - prevJavaAvg) / prevJavaAvg) * 100 : 0;
  const nationalChangePct = prevNationalAvg ? ((nationalAvg - prevNationalAvg) / prevNationalAvg) * 100 : 0;

  let trend = "stable";
  if (javaChangePct > 0.1) {
    trend = "up";
  } else if (javaChangePct < -0.1) {
    trend = "down";
  }

  return {
    latestDate: latest.tanggal,
    javaAvg,
    nationalAvg,
    javaChangePct,
    nationalChangePct,
    highPrice,
    lowPrice,
    trend,
    latestRecord: latest
  };
}

function getChartData(timeframe) {
  const prices = window.Database.getPrices();
  if (prices.length === 0) return { labels: [], datasets: [] };

  const sorted = [...prices].sort((a, b) => new Date(a.tanggal) - new Date(b.tanggal));
  let targetRecords = [...sorted];
  const now = new Date();

  if (timeframe === "hari") {
    targetRecords = sorted.filter(r => {
      const diffTime = Math.abs(now - new Date(r.tanggal));
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      return diffDays <= 15;
    });
  } else if (timeframe === "minggu") {
    targetRecords = sorted.filter(r => {
      const diffTime = Math.abs(now - new Date(r.tanggal));
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      return diffDays <= 30;
    });
  } else if (timeframe === "bulan") {
    targetRecords = sorted.filter(r => {
      const diffTime = Math.abs(now - new Date(r.tanggal));
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      return diffDays <= 90;
    });
  }

  const colors = {
    'jawa': '#3B82F6',
    'nasional': '#10B981',
    'tertinggi': '#F59E0B',
    'terendah': '#EF4444'
  };

  const datasets = [
    {
      label: 'Rata-rata Jawa',
      data: targetRecords.map(r => r.harga_jawa),
      borderColor: colors['jawa'],
      backgroundColor: colors['jawa'] + '10',
      borderWidth: 2,
      tension: 0.3,
      fill: false
    },
    {
      label: 'Rata-rata Nasional',
      data: targetRecords.map(r => r.harga_nasional),
      borderColor: colors['nasional'],
      backgroundColor: colors['nasional'] + '10',
      borderWidth: 2,
      tension: 0.3,
      fill: false
    },
    {
      label: 'Harga Tertinggi',
      data: targetRecords.map(r => r.harga_tertinggi),
      borderColor: colors['tertinggi'],
      backgroundColor: 'transparent',
      borderWidth: 2,
      borderDash: [5, 5],
      tension: 0.3,
      fill: false
    },
    {
      label: 'Harga Terendah',
      data: targetRecords.map(r => r.harga_terendah),
      borderColor: colors['terendah'],
      backgroundColor: 'transparent',
      borderWidth: 2,
      borderDash: [5, 5],
      tension: 0.3,
      fill: false
    }
  ];

  const labels = targetRecords.map(r => {
    const parts = r.tanggal.split('-');
    if (parts.length === 3) return `${parts[2]}/${parts[1]}`;
    return r.tanggal;
  });

  return { labels, datasets };
}

let priceChartInstance = null;

window.renderPriceChart = function(timeframe = "hari") {
  const canvas = document.getElementById('priceChart');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const chartData = getChartData(timeframe);

  if (priceChartInstance) {
    priceChartInstance.destroy();
  }

  priceChartInstance = new Chart(ctx, {
    type: 'line',
    data: {
      labels: chartData.labels,
      datasets: chartData.datasets
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: {
        mode: 'index',
        intersect: false
      },
      plugins: {
        legend: {
          position: 'top',
          labels: {
            usePointStyle: true,
            boxWidth: 8,
            font: {
              family: 'Inter, sans-serif',
              size: 11
            }
          }
        },
        tooltip: {
          padding: 12,
          bodySpacing: 6,
          titleFont: {
            family: 'Outfit, sans-serif',
            weight: 'bold'
          },
          bodyFont: {
            family: 'Inter, sans-serif'
          },
          callbacks: {
            label: function(context) {
              let label = context.dataset.label || '';
              if (label) label += ': ';
              if (context.parsed.y !== null) {
                label += formatRupiah(context.parsed.y) + '/kg';
              }
              return label;
            }
          }
        }
      },
      scales: {
        x: {
          grid: {
            display: false
          },
          ticks: {
            font: {
              family: 'Inter, sans-serif',
              size: 10
            }
          }
        },
        y: {
          ticks: {
            callback: function(value) {
              return 'Rp ' + (value / 1000) + 'k';
            },
            font: {
              family: 'Inter, sans-serif',
              size: 10
            }
          },
          grid: {
            color: 'rgba(0, 0, 0, 0.05)'
          }
        }
      }
    }
  });
};

