window.switchPriceTab = function(timeframe) {
  const tabs = ["hari", "minggu", "bulan", "tahun"];
  tabs.forEach(t => {
    const el = document.getElementById(`btn-tab-${t}`);
    if (el) {
      if (t === timeframe) {
        el.classList.add("active");
      } else {
        el.classList.remove("active");
      }
    }
  });

  window.renderPriceChart(timeframe);
};

window.filterSheepPricesTable = function() {
  const searchVal = document.getElementById("price-search-date").value;
  const periodVal = document.getElementById("price-filter-period").value;
  const sourceVal = document.getElementById("price-filter-source") ? document.getElementById("price-filter-source").value : "all";

  const prices = window.Database.getPrices();
  let filtered = [...prices];

  if (sourceVal !== "all") {
    if (sourceVal === "manual") {
      filtered = filtered.filter(p => p.sumber !== "Sistem Otomatis");
    } else {
      filtered = filtered.filter(p => p.sumber === "Sistem Otomatis");
    }
  }

  if (searchVal) {
    filtered = filtered.filter(p => p.tanggal.includes(searchVal));
  }

  const now = new Date();
  if (periodVal === "7") {
    filtered = filtered.filter(p => {
      const diffTime = Math.abs(now - new Date(p.tanggal));
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      return diffDays <= 7;
    });
  } else if (periodVal === "30") {
    filtered = filtered.filter(p => {
      const diffTime = Math.abs(now - new Date(p.tanggal));
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      return diffDays <= 30;
    });
  }

  filtered.sort((a, b) => new Date(b.tanggal) - new Date(a.tanggal));

  const tbody = document.getElementById("prices-table-body");
  if (!tbody) return;

  if (filtered.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="7" style="text-align: center; color: var(--text-muted); padding: 2rem;">
          Tidak ada rekam harga yang cocok dengan filter.
        </td>
      </tr>
    `;
    return;
  }

  tbody.innerHTML = filtered.map(p => `
    <tr>
      <td data-label="Tanggal">${formatDate(p.tanggal)}</td>
      <td data-label="Avg Jawa">${formatRupiah(p.harga_jawa)}/kg</td>
      <td data-label="Avg Nasional">${formatRupiah(p.harga_nasional)}/kg</td>
      <td data-label="Tertinggi" style="color: #10B981; font-weight: 500;">${formatRupiah(p.harga_tertinggi)}/kg</td>
      <td data-label="Terendah" style="color: #EF4444; font-weight: 500;">${formatRupiah(p.harga_terendah)}/kg</td>
      <td data-label="Sumber"><span class="badge" style="background-color: ${p.sumber === 'Sistem Otomatis' ? '#10B981' : '#6B7280'}; color: white; padding: 2px 8px; border-radius: 4px; font-size: 0.75rem; font-weight: 600;">${p.sumber}</span></td>
      <td data-label="Aksi" class="table-actions" style="text-align: center;">
        <button class="btn btn-icon btn-danger" onclick="confirmDeletePrice('${p.id}')" title="Hapus">🗑️</button>
      </td>
    </tr>
  `).join('');
};

window.triggerAutomatedFetch = async function() {
  try {
    const btn = document.querySelector('button[onclick="triggerAutomatedFetch()"]');
    btn.disabled = true;
    btn.innerHTML = `<span class="icon">⌛</span> <span>Menarik Data...</span>`;

    await window.Database.fetchAutomatedPrices();

    showToast("Berhasil menyinkronkan data harga otomatis! 📈", "success");
    router();
  } catch (err) {
    console.error(err);
    showToast(err.message || "Gagal menarik data harga otomatis.", "danger");
    router();
  }
};

