window.savePriceForm = async function(e) {
  e.preventDefault();
  const tanggal = document.getElementById("price-date").value;
  const hargaJawa = parseInt(document.getElementById("price-jawa").value, 10);
  const hargaNasional = parseInt(document.getElementById("price-nasional").value, 10);
  const hargaTertinggi = parseInt(document.getElementById("price-tertinggi").value, 10);
  const hargaTerendah = parseInt(document.getElementById("price-terendah").value, 10);
  const sumber = document.getElementById("price-sumber").value;

  if (!tanggal || !hargaJawa || !hargaNasional || !hargaTertinggi || !hargaTerendah || !sumber) {
    showToast("Harap isi semua input form.", "danger");
    return;
  }

  if (hargaTertinggi < hargaTerendah) {
    showToast("Harga tertinggi tidak boleh kurang dari harga terendah.", "warning");
    return;
  }

  try {
    const submitBtn = e.target.querySelector('button[type="submit"]');
    submitBtn.disabled = true;
    submitBtn.textContent = "Menyimpan...";

    await window.Database.addPrice({
      tanggal,
      hargaJawa,
      hargaNasional,
      hargaTertinggi,
      hargaTerendah,
      sumber
    });
    closeModal();
    showToast("Entri summary harga berhasil disimpan! 📈", "success");
    router();
  } catch (err) {
    console.error(err);
    showToast(err.message || "Gagal mencatat harga domba.", "danger");
    e.target.querySelector('button[type="submit"]').disabled = false;
    e.target.querySelector('button[type="submit"]').textContent = "Simpan Entri";
  }
};

window.confirmDeletePrice = function(id) {
  const formHTML = `
    <div style="padding: 1rem 0;">
      <p style="margin-bottom: 1.5rem; color: var(--text-muted); font-size: 0.95rem;">Apakah Anda yakin ingin menghapus rekam harga domba ini? Tindakan ini tidak dapat dibatalkan.</p>
      <div class="form-actions">
        <button type="button" class="btn btn-secondary" onclick="closeModal()">Batal</button>
        <button type="button" class="btn btn-danger" onclick="deletePriceAction('${id}')">Hapus</button>
      </div>
    </div>
  `;
  openModal("Konfirmasi Hapus Harga", formHTML);
};

window.deletePriceAction = async function(id) {
  try {
    await window.Database.deletePrice(id);
    closeModal();
    showToast("Rekam harga domba berhasil dihapus.", "success");
    router();
  } catch (err) {
    console.error(err);
    showToast("Gagal menghapus rekam harga.", "danger");
  }
};

window.exportPricesToExcel = function() {
  const prices = window.Database.getPrices();
  if (prices.length === 0) {
    showToast("Tidak ada data untuk diekspor.", "warning");
    return;
  }

  const sorted = [...prices].sort((a, b) => new Date(b.tanggal) - new Date(a.tanggal));
  const headers = ["Tanggal", "Rata-rata Jawa (IDR)", "Rata-rata Nasional (IDR)", "Tertinggi (IDR)", "Terendah (IDR)", "Sumber"];
  const rows = sorted.map(p => [
    p.tanggal,
    p.harga_jawa,
    p.harga_nasional,
    p.harga_tertinggi,
    p.harga_terendah,
    p.sumber
  ]);

  const csvContent = "\uFEFF" + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `harga_domba_brm_${new Date().toISOString().split('T')[0]}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  showToast("File Excel/CSV berhasil diunduh!", "success");
};

window.exportPricesToPDF = function() {
  const prices = window.Database.getPrices();
  if (prices.length === 0) {
    showToast("Tidak ada data untuk dicetak.", "warning");
    return;
  }

  const sorted = [...prices].sort((a, b) => new Date(b.tanggal) - new Date(a.tanggal));
  const printWindow = window.open("", "_blank");
  if (!printWindow) {
    showToast("Popup diblokir oleh browser. Harap izinkan popup.", "danger");
    return;
  }

  const tableRows = sorted.map(p => `
    <tr>
      <td>${formatDate(p.tanggal)}</td>
      <td class="price-col">${formatRupiah(p.harga_jawa)}/kg</td>
      <td class="price-col">${formatRupiah(p.harga_nasional)}/kg</td>
      <td style="color: #047857; font-weight: 600;">${formatRupiah(p.harga_tertinggi)}/kg</td>
      <td style="color: #B91C1C; font-weight: 600;">${formatRupiah(p.harga_terendah)}/kg</td>
      <td>${p.sumber}</td>
    </tr>
  `).join('');

  const stats = calculateSheepPriceStats();

  printWindow.document.write(`
    <html>
      <head>
        <title>SITernak Bagus Rejo Mulyo - Laporan Harga Domba</title>
        <style>
          body {
            font-family: 'Inter', 'Segoe UI', Helvetica, Arial, sans-serif;
