            margin-bottom: 2rem;
            border-bottom: 2px solid #059669;
            padding-bottom: 1.5rem;
          }
          .header h1 {
            margin: 0;
            color: #047857;
            font-size: 1.8rem;
            font-weight: 700;
          }
          .header p {
