          }
          .meta-info {
            display: flex;
            justify-content: space-between;
            margin-bottom: 1.5rem;
            font-size: 0.88rem;
          }
          .summary-box {
            background-color: #F0FDF4;
            border: 1px solid #BBF7D0;
            border-radius: 8px;
            padding: 1rem;
            margin-bottom: 2rem;
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 1rem;
          }
          .summary-item {
            text-align: center;
          }
          .summary-item .label {
            font-size: 0.75rem;
            color: #065F46;
            text-transform: uppercase;
            font-weight: 600;
            margin-bottom: 4px;
            display: block;
          }
          .summary-item .value {
            font-size: 1.25rem;
            font-weight: 700;
            color: #047857;
          }
          table {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 2rem;
          }
          th {
            background-color: #059669;
            color: white;
            font-weight: 600;
            text-align: left;
            padding: 10px 12px;
            font-size: 0.9rem;
          }
          td {
            padding: 10px 12px;
            border-bottom: 1px solid #E5E7EB;
            font-size: 0.88rem;
          }
          tr:nth-child(even) td {
            background-color: #F9FAFB;
          }
          .price-col {
