            }
          }
        </style>
      </head>
      <body>
        <div class="header">
          <h1>SITernak Bagus Rejo Mulyo</h1>
          <p>Laporan Pemantauan Harga Domba Kelompok Ternak</p>
          <p style="font-size: 0.8rem; color: #9CA3AF;">Bagusan RT 02 RW 07, Sendangijo, Selogiri, Wonogiri, Jawa Tengah</p>
        </div>

        <div class="meta-info">
          <div>Dicetak Oleh: Sistem Informasi Kelompok Ternak</div>
          <div>Tanggal Cetak: ${formatDate(new Date())}</div>
        </div>

        <div class="summary-box">
          <div class="summary-item">
            <span class="label">Rata-rata Jawa</span>
            <span class="value">${formatRupiah(Math.round(stats.javaAvg))}/kg</span>
